const AWS = require('aws-sdk');
const axios = require('axios');
const dynamoDB = new AWS.DynamoDB.DocumentClient();
const sqs = new AWS.SQS();

const PAYMENT_API_URL = process.env.PAYMENT_API_URL;
const DYNAMODB_TABLE_NAME = process.env.DYNAMODB_TABLE_NAME;
const SQS_QUEUE_URL = process.env.SQS_QUEUE_URL;

exports.handler = async (event) => {
  for (const record of event.Records) {
    try {
      const order = JSON.parse(record.body);
      validateOrder(order);

      const paymentResponse = await processPayment(order);
      await updateOrderStatus(order.orderId, paymentResponse);

    } catch (error) {
      console.error('Error processing order:', error);
    }
  }
};

function validateOrder(order) {
  if (!order || typeof order !== 'object' || !order.orderId || !order.amount) {
    throw new Error('Invalid order data');
  }
}

async function processPayment(order) {
  try {
    const response = await axios.post(PAYMENT_API_URL, {
      orderId: order.orderId,
      amount: order.amount
    }, {
      headers: {
        'Authorization': `Bearer ${process.env.PAYMENT_API_TOKEN}`
      }
    });

    if (response.status !== 200) {
      throw new Error('Payment API error');
    }

    return response.data;
  } catch (error) {
    console.error('Payment processing error:', error);
    throw error;
  }
}

async function updateOrderStatus(orderId, paymentResponse) {
  try {
    const params = {
      TableName: DYNAMODB_TABLE_NAME,
      Key: { orderId },
      UpdateExpression: 'set paymentStatus = :status, paymentDetails = :details',
      ExpressionAttributeValues: {
        ':status': paymentResponse.status,
        ':details': paymentResponse.details
      }
    };

    await dynamoDB.update(params).promise();
  } catch (error) {
    console.error('Error updating DynamoDB:', error);
    throw error;
  }
}